import{_ as t,c as s,a as i,o as a}from"./app-CEcM0piI.js";const d={};function n(r,e){return a(),s("div",null,e[0]||(e[0]=[i(`<ol><li>浏览器是JavaScript的前端运行环境</li><li>Node.js是JavaScript的后端运行环境。</li><li>Node.js中无法调用DOM和BOM等浏览器内置API。</li></ol><h1 id="系统模块" tabindex="-1"><a class="header-anchor" href="#系统模块"><span>系统模块</span></a></h1><h2 id="fs" tabindex="-1"><a class="header-anchor" href="#fs"><span>fs</span></a></h2><p>fs模块是Nodejs官方提供的、用来操作文件的模块。它提供了一系列的方法和属性，用来满足用户对文件的操作需求。</p><table><thead><tr><th>函数</th><th>作用</th></tr></thead><tbody><tr><td>readFile</td><td>读取指定文件中的内容,参数一：读取的文件路径。参数二（可选）：读取文件时采用的编码。参数三：回调函数，回调函数有两个参数：第一个参数是如果读取失败传入的错误信息，第二个参数是如果读取成功传入的内容，读取成功时err的值是null，读取失败时datastr的值是undefine</td></tr><tr><td>writeFile</td><td>向指定的文件中写入内容，和readFile的参数一样，但多了一个参数为要写入的内容</td></tr></tbody></table><h2 id="path" tabindex="-1"><a class="header-anchor" href="#path"><span>path</span></a></h2><p>path模块是Node.js官方提供的、用来处理路径的模块。它提供了一系列的方法和属性，用来满足用户对路径的处理需求。</p><table><thead><tr><th>函数</th><th>作用</th></tr></thead><tbody><tr><td>__dirname</td><td>当前文件所在目录</td></tr><tr><td>join</td><td>将多个路径片段拼接成一个完整的路径字符串</td></tr><tr><td>basename</td><td>从路径字符串中将文件名解析出来。参数1：路径字符串，参数2：文件扩展名</td></tr><tr><td>extname</td><td>返回文件扩展名。参数1：文件路径</td></tr></tbody></table><h2 id="http" tabindex="-1"><a class="header-anchor" href="#http"><span>http</span></a></h2><p>http模块是Nodejs官方提供的、用来创建web服务器的模块。</p><table><thead><tr><th>函数</th><th>作用</th></tr></thead><tbody><tr><td>createServer</td><td>创建服务器对象</td></tr><tr><td>on</td><td>为服务器对象绑定事件，参数1：绑定的时间名，参数2：触发事件时的回调，回调中的第一个参数是接收到的请求，第二个参数是返回给客户端的响应对象</td></tr><tr><td>listen</td><td>启动服务器，参数1：监听的端口号，参数2：回调函数</td></tr><tr><td>end</td><td>向客户端响应内容</td></tr><tr><td>setHeader</td><td>给res对象设置响应头</td></tr></tbody></table><h1 id="module对象" tabindex="-1"><a class="header-anchor" href="#module对象"><span>module对象</span></a></h1><p>在每个js自定义模块中都有一个module对象，它里面存储了和当前模块有关的信息</p><p>由于module.exports单词写起来比较复杂，为了简化向外共享成员的代码，Node提供了exports对象。默认情况下，exports和module.exports指向同一个对象。最终共享的结果，还是以module.exports指向的对象为准。</p><h1 id="模块加载机制" tabindex="-1"><a class="header-anchor" href="#模块加载机制"><span>模块加载机制</span></a></h1><p>npm优先从缓存中加载模块，如果缓存中有了就不会去磁盘中加载了，一个模块只会加载一次</p><p><strong>优先加载内置模块</strong> 内置模块是由Nodejs官方提供的模块，内置模块的加载优先级最高。 例如，require(&#39;fs&#39;）始终返回内置的fs模块，即使在node_modules目录下有名字相同的包也叫做fs。</p><p>使用requireO加载自定义模块时以/或/开头的路径标识符。在加载自定义模块时，如果没有指定/或./ 这样的路径标识符，则node会把它当作<strong>内置模块</strong>或<strong>第三方模块</strong>进行加载。</p><p>在使用require0导入自定义模块时，如果省略了文件的扩展名，会按顺序分别尝试加载以下的文件：</p><ol><li>按照确切的文件名进行加载</li><li>补全js扩展名进行加载</li><li>补全json扩展名进行加载</li><li>补全.node扩展名进行加载</li><li>加载失败，终端报错</li></ol><p><strong>第三方模块加载机制</strong> 如果传递给requireO的模块标识符不是一个内置模块，也没有以‘/”或‘./”开头，则Node.js会从当前模块的父目录开始，尝试从/nodemodules文件夹中加载第三方模块。 如果没有找到对应的第三方模块，则移动到再上一层父目录中，进行加载，直到文件系统的根目录。</p><p>当把目录作为模块标识符，传递给require进行加载的时候，有三种加载方式：</p><ol><li>在被加载的目录下查找一个叫做 packagejson 的文件，并寻找 main 属性，作为 requireO 加载的入口</li><li>如果目录里没有 package.json 文件，或者 main 入口不存在或无法解析，则 Node.js 将会试图加载目录下的 indexjs 文件。</li><li>如果以上两步都失败了，则 Node.js 会在终端打印错误消息，报告模块的缺失：Error:Cannot find module&#39;xxx&#39;</li></ol><h1 id="nodemon" tabindex="-1"><a class="header-anchor" href="#nodemon"><span>nodemon</span></a></h1><p>热重载项目</p><p>下载后使用nodemon命令启动项目</p><h1 id="express" tabindex="-1"><a class="header-anchor" href="#express"><span>Express</span></a></h1><p>Express的作用和Node.js内置的http模块类似，是专门用来创建Web服务器的 提供了快速创建Web服务器的便捷方法。</p><p>http内置模块用起来很复杂，开发效率低；Express是基于内置的http模块进一步封装出来的，能够极大的提高开发效率。</p><table><thead><tr><th>函数</th><th>作用</th></tr></thead><tbody><tr><td>express</td><td>创建服务器对象</td></tr><tr><td>get</td><td>为服务器对象设置监听get请求，参数1：请求的url，参数2：回调函数，回调函数的第一个参数请求体，第二个参数响应数据</td></tr><tr><td>post</td><td>监听post请求</td></tr><tr><td>res.send</td><td>响应内容</td></tr><tr><td>req.query</td><td>获取到请求中的参数，json对象</td></tr><tr><td>req.params</td><td>获取到url中通过:匹配的动态参数,&#39;/index/:id&#39;</td></tr><tr><td>static</td><td>创建静态资源服务器，指定将哪个文件夹部署到静态资源服务器</td></tr></tbody></table><h1 id="npm" tabindex="-1"><a class="header-anchor" href="#npm"><span>npm</span></a></h1><p>查看npm配置信息</p><ul><li>-l：查看详细信息</li></ul><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npm config ls</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>查看npm仓库源</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npm config get registry</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>设置npm仓库源</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npm config set registry http://registry.npm.taobao.org</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>配置缓存路径</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npm config set cache &quot;D:\\Develop\\npm-cache&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>配置npm库全局安装路径</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>npm config set prefix &quot;D:\\Develop\\npm-global&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>配置pnpm</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>pnpm config set global-bin-dir &quot;D:\\Develop\\.pnpm-store&quot;</span></span>
<span class="line"><span>pnpm config set cache-dir &quot;D:\\Develop\\.pnpm-store\\cache&quot;</span></span>
<span class="line"><span>pnpm config set state-dir &quot;D:\\Develop\\.pnpm-store\\state&quot;</span></span>
<span class="line"><span>pnpm config set global-dir-dir &quot;D:\\Develop\\.pnpm-store\\global&quot;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,44)]))}const p=t(d,[["render",n]]),h=JSON.parse('{"path":"/front/node/1/","title":"node","lang":"zh-CN","frontmatter":{"title":"node","createTime":"2025/06/18 21:13:08","permalink":"/front/node/1/"},"readingTime":{"minutes":4.94,"words":1483},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/node/node.md","headers":[]}');export{p as comp,h as data};
